DarkRPUI = DarkRPUI or {}
local doorClasses={func_door=true,func_door_rotating=true,prop_door_rotating=true}
hook.Add("HUDPaint","DarkRPUI.DoorText",function()
 local ply=LocalPlayer(); if not IsValid(ply) then return end; local tr=ply:GetEyeTrace(); local ent=tr.Entity; if not IsValid(ent) or tr.HitPos:DistToSqr(ply:EyePos())>140*140 or not doorClasses[ent:GetClass()] then return end
 local title="Door"; local body="Press F2 for actions"; local owner=ent.getDoorOwner and ent:getDoorOwner(); if IsValid(owner) then title="Owned"; body=owner:Nick() elseif ent.getKeysNonOwnable and ent:getKeysNonOwnable() then title="Unavailable"; body="This property cannot be purchased" else title="For Sale"; body="Press F2 to purchase" end
 surface.SetFont("DarkRPUI.Body"); local tw=math.max(surface.GetTextSize(body),surface.GetTextSize(title))+36; local x,y=DarkRPUI.Layout.ClampToScreen(ScrW()/2-tw/2,ScrH()/2+72,tw,64); DarkRPUI.UI.ShadowedBox(14,x,y,tw,64,DarkRPUI.Color("glass"),DarkRPUI.Color("border"),110); DarkRPUI.UI.Text(title,"DarkRPUI.Subtitle",x+tw/2,y+12,DarkRPUI.Color("text"),TEXT_ALIGN_CENTER); DarkRPUI.UI.Text(body,"DarkRPUI.Small",x+tw/2,y+38,DarkRPUI.Color("subtext"),TEXT_ALIGN_CENTER)
end)
hook.Add("PlayerBindPress","DarkRPUI.DoorRadial",function(_,bind,pressed) if not pressed or not bind:find("gm_showteam",1,true) then return end; local tr=LocalPlayer():GetEyeTrace(); if IsValid(tr.Entity) and doorClasses[tr.Entity:GetClass()] then DarkRPUI.OpenRadial({{label="Buy",icon="$",callback=function() RunConsoleCommand("say","/buy") end},{label="Sell",icon="↩",callback=function() RunConsoleCommand("say","/sell") end},{label="Lock",icon="🔒",callback=function() RunConsoleCommand("say","/lock") end},{label="Unlock",icon="🔓",callback=function() RunConsoleCommand("say","/unlock") end},{label="Close",icon="×"}}, {title="Door"}); return true end end)
